import{_ as p}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o as s,c as o,a as e,b as r,d as i,e as t}from"./app-706bfe03.js";const c={},d=t('<h1 id="前后端" tabindex="-1"><a class="header-anchor" href="#前后端" aria-hidden="true">#</a> 前后端</h1><h2 id="客户端渲染-csr" tabindex="-1"><a class="header-anchor" href="#客户端渲染-csr" aria-hidden="true">#</a> 客户端渲染 CSR</h2><p>客户端渲染 (client-side rendering, CSR)</p><p>服务器在 SPA 中的作用主要是提供静态资产 HTML、JS 和 CSS 和 RESTful API。</p><p><img src="https://www.workingsoftware.dev/content/images/2022/12/image-23.png" alt="img"></p><p>优势</p><ul><li>第一个字节所需时间短</li><li>高度交互式网络应用程序的用户体验</li><li>自主前端测试</li><li>前端与服务器之间的松耦合</li><li>提供服务器端 HTTP API</li></ul><p>缺点</p><ul><li>首次内容绘制与交互时间之间可能存在较大差距</li><li>不适合搜索引擎优化和社交媒体预览</li><li>复杂性和技术异质性</li><li>客户端的计算资源</li></ul><h2 id="服务端渲染-ssr" tabindex="-1"><a class="header-anchor" href="#服务端渲染-ssr" aria-hidden="true">#</a> 服务端渲染 SSR</h2><p>Resource Oriented Client Architecture (ROCA)</p><p>使用服务器渲染技术时，前端完全在服务器端渲染</p><p>通常情况下，后台会有一个表现层或表现层。表现层或表现层包含一个模板引擎，可将动态 HTML 转换为静态 HTML。</p><p>好在由于 JavaScript 占用较少，第一次绘制内容和交互时间之间的差别不大</p><p>另一方面，由于每次页面请求都需要在服务器端完成渲染任务，因此到第一个字节的时间较长。</p><p>服务器端渲染技术支持面向资源的客户端架构（ROCA）风格。</p>',16),h={href:"https://roca-style.org/index.html?ref=workingsoftware.dev",target:"_blank",rel:"noopener noreferrer"},l=t('<p>ROCA 的一些重要原则：</p><p>服务器遵循 REST。所有资源都有唯一的 URL。 通过 URL 标识的资源也可能有其他表示法（如 JSON / XML）。 所有逻辑都位于服务器上。 JavaScript 仅用于优化用户界面。 浏览器控件（如后退、前进和刷新按钮）应能正常工作。 HTML 不包含布局信息。 应用程序无需 JavaScript 即可使用。 不应在客户端和服务器上重复执行逻辑。</p><p>优势</p><p>首次绘制内容与交互时间之间的差异很小 改进性能和用户体验，因为初始 HTML 是在服务器上生成的，可以快速传送到客户端（快速交互时间）。 简化了代码库，因为所有逻辑都只在服务器上执行，没有冗余 只需发布服务器 带宽小、速度快，因为只需传输 HTML 代码 JavaScript 代码或 JS 代码传输中的错误只会导致应用程序的可用性降低，但仍可使用</p><p>缺点</p><p>到第一个字节的时间增加 难以实现具有高度交互要求的前端 浏览器缓存能力有限，因为初始 HTML 是在服务器而非客户端生成的。</p><h2 id="静态资源生成-static-site-generation-ssg" tabindex="-1"><a class="header-anchor" href="#静态资源生成-static-site-generation-ssg" aria-hidden="true">#</a> 静态资源生成 Static Site Generation ( SSG )</h2><blockquote><p>A modern web development architecture is based on client-side JavaScript, reusable APIs, and pre-built markup.</p></blockquote><p>JAM Stack JavaScript, reusable APIs, and pre-built markup.</p><p>这就是 JAM 堆栈的诞生，它主要通过静态页面生成（SSG）来促进静态渲染。</p><p>优势</p><p>改善性能和用户体验，因为初始 HTML 是由静态文件生成和提供的，并可被浏览器缓存（TTFB、FCP 和 TTI）。 提高安全性，因为静态文件不会受到常见的安全威胁，如 SQL 注入或跨站脚本攻击。 简化了代码库和开发工作流程，因为所有渲染都是在构建时完成的，无需服务器端语言或框架。 提高了可扩展性和可靠性，因为静态文件可以很容易地从全球内容交付网络（CDN）分发和提供。 缺点</p><p>对复杂或动态内容的支持有限（不灵活），因为内容必须预先生成，不能实时更新。 开发和维护成本增加，因为 SSG 需要额外的工具和流程来生成和管理静态内容。 导致客户端/水合</p><h2 id="预渲染-pre-rendering" tabindex="-1"><a class="header-anchor" href="#预渲染-pre-rendering" aria-hidden="true">#</a> 预渲染 Pre-Rendering</h2><p>在这种情况下，您会在构建时运行单页应用程序，将其初始状态捕获为静态 HTML。在第一次调用时，将其作为静态 HTML 发送。</p><p>优势</p><p>改进性能和用户体验，因为初始 HTML 是在客户端生成的，可被浏览器缓存（TTFB、FCP）。 改善搜索引擎优化，因为搜索引擎可以抓取并索引在客户端生成的初始 HTML。 简化代码库，因为所有渲染都在客户端完成，无需管理服务器端渲染。 提高了灵活性，可以在初始预渲染过程完成之前在客户端执行某些操作或访问某些信息。 减少服务器负载和潜在的性能问题，因为渲染是在客户端而不是服务器上进行的。 缺点</p><p>预渲染复杂或动态内容的能力有限，因为初始 HTML 必须在服务器上生成。 开发和维护成本增加，因为预渲染需要额外的工具和流程。</p><h2 id="同构渲染-isomorphic" tabindex="-1"><a class="header-anchor" href="#同构渲染-isomorphic" aria-hidden="true">#</a> 同构渲染 Isomorphic</h2><p>在这种情况下，每次导航变化（即 HTTP 请求）都会导致单页应用程序的服务器端渲染。</p><p>预先渲染的页面将作为 HTTP 响应返回前端，然后在客户端再次启动网络应用程序。</p><p>因此，网络应用程序将从交互性不强过渡到完全交互。</p><p>优势</p><p>提高前端页面的性能和渲染速度（良好的 FCP） 更好的搜索引擎优化，改进动态内容的搜索引擎索引，改进社交媒体帖子的预览生成 可预先渲染页面，改善网络连接速度较慢用户的用户体验 提高安全性，防止跨站脚本攻击 支持速度较慢的网络连接 缺点</p><p>由于需要管理服务器端和客户端渲染，代码库的复杂性增加。 由于在服务器上渲染（FCP 和 TTI 之间的延迟），增加了服务器负载和潜在的性能问题。 浏览器缓存功能有限，因为初始 HTML 是在服务器而非客户端生成的。 潜在的搜索引擎优化挑战，因为搜索引擎可能无法抓取和索引客户端生成的动态内容。 在初始水合过程完成之前，客户端执行某些操作或访问某些信息的能力有限。</p><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>',26),u={href:"https://www.workingsoftware.dev/frontend-rendering-techniques/",target:"_blank",rel:"noopener noreferrer"};function T(S,f){const a=n("ExternalLinkIcon");return s(),o("div",null,[d,e("p",null,[e("a",h,[r("ROCA"),i(a)]),r(" 是一套简单的网络应用程序前端建议。")]),l,e("p",null,[e("a",u,[r("Which web frontend architecture fits best?"),i(a)]),r(", workingsoftware.dev")])])}const g=p(c,[["render",T],["__file","前后端.html.vue"]]);export{g as default};
